#!/usr/bin/env python3
"""
convert.py - Convert AI conversation logs to Markdown

Usage:
    python convert.py -f FORMAT input.json output.md
    python convert.py input.json output.md  # interactive format selection

Formats: claude, codebuddy, codex, gemini
"""

import argparse
import json
import sys
from pathlib import Path


# === Content Cleaning ===

import re

# Patterns to strip from AI internal messages
CLEAN_PATTERNS = [
    # Claude Code patterns
    (re.compile(r'<local-command-caveat>.*?</local-command-caveat>', re.DOTALL), ""),
    (re.compile(r'<local-command-stdout>(.*?)</local-command-stdout>', re.DOTALL), r"\1"),
    (re.compile(r'<local-command-stderr>(.*?)</local-command-stderr>', re.DOTALL), r"\1"),
    (re.compile(r'<command-name>(.*?)</command-name>\s*<command-message>(.*?)</command-message>\s*<command-args>(.*?)</command-args>', re.DOTALL), r"`\1 \2 \3`"),
    # CodeBuddy patterns (different tag order)
    (re.compile(r'<command-message>(.*?)</command-message>\s*<command-name>(.*?)</command-name>', re.DOTALL), r"`\2 \1`"),
    (re.compile(r'<thinking>.*?</thinking>', re.DOTALL), ""),
    (re.compile(r'\n{3,}'), "\n\n"),  # Collapse multiple blank lines
]

def clean_text(text: str) -> str:
    """Remove Claude internal tags and normalize whitespace."""
    for pattern, replacement in CLEAN_PATTERNS:
        text = pattern.sub(replacement, text)
    return text.strip()


# === Format Parsers ===

def parse_claude_jsonl(lines: list[str]) -> list[dict]:
    """Parse Claude Code JSONL format."""
    messages = []
    for line in lines:
        if not line.strip():
            continue
        entry = json.loads(line)

        # Skip non-message entries and meta messages
        msg_type = entry.get("type", "")
        if msg_type not in ("user", "assistant"):
            continue
        if entry.get("isMeta") or entry.get("isSummary"):
            continue

        # Get message data from 'message' field
        message_data = entry.get("message", {})
        role = message_data.get("role", msg_type)
        msg = {"role": role, "content": []}

        # Extract content blocks
        content = message_data.get("content", [])
        if isinstance(content, str):
            # Simple text message - clean it
            cleaned = clean_text(content)
            if cleaned:
                msg["content"].append({"type": "text", "text": cleaned})
        elif isinstance(content, list):
            for block in content:
                if block.get("type") == "text":
                    cleaned = clean_text(block.get("text", ""))
                    if cleaned:
                        msg["content"].append({"type": "text", "text": cleaned})
                elif block.get("type") == "tool_use":
                    msg["content"].append({
                        "type": "tool_call",
                        "name": block.get("name", ""),
                        "input": block.get("input", {})
                    })
                elif block.get("type") == "tool_result":
                    msg["content"].append({
                        "type": "tool_result",
                        "content": block.get("content", "")
                    })

        messages.append(msg)
    return messages


def parse_codebuddy_jsonl(lines: list[str]) -> list[dict]:
    """Parse CodeBuddy JSONL format."""
    messages = []
    for line in lines:
        if not line.strip():
            continue
        entry = json.loads(line)

        msg_type = entry.get("type", "")

        # Skip non-conversation entries
        if msg_type not in ("message", "function_call", "function_call_result"):
            continue

        if msg_type == "message":
            role = entry.get("role", "unknown")
            msg = {"role": role, "content": []}

            # Extract content from content array
            for block in entry.get("content", []):
                block_type = block.get("type", "")
                if block_type in ("input_text", "output_text"):
                    cleaned = clean_text(block.get("text", ""))
                    if cleaned:
                        msg["content"].append({"type": "text", "text": cleaned})

            if msg["content"]:
                messages.append(msg)

        elif msg_type == "function_call":
            msg = {"role": "assistant", "content": [{
                "type": "tool_call",
                "name": entry.get("name", ""),
                "input": json.loads(entry.get("arguments", "{}"))
            }]}
            messages.append(msg)

        elif msg_type == "function_call_result":
            output = entry.get("output", {})
            content = output.get("text", "") if isinstance(output, dict) else str(output)
            msg = {"role": "tool", "content": [{
                "type": "tool_result",
                "name": entry.get("name", ""),
                "content": content
            }]}
            messages.append(msg)

    return messages


def parse_codex_jsonl(lines: list[str]) -> list[dict]:
    """Parse OpenAI Codex JSONL format."""
    messages = []
    for line in lines:
        if not line.strip():
            continue
        entry = json.loads(line)

        entry_type = entry.get("type", "")

        # Only process response_item with message content
        if entry_type != "response_item":
            continue

        payload = entry.get("payload", {})
        payload_type = payload.get("type", "")

        # Skip reasoning items (encrypted content)
        if payload_type == "reasoning":
            continue

        # Handle messages
        if payload_type == "message":
            role = payload.get("role", "unknown")
            # Skip developer/system instructions
            if role in ("developer", "system"):
                continue

            msg = {"role": role, "content": []}

            for block in payload.get("content", []):
                block_type = block.get("type", "")
                if block_type in ("input_text", "output_text"):
                    text = block.get("text", "")
                    if text:
                        msg["content"].append({"type": "text", "text": text})

            if msg["content"]:
                messages.append(msg)

        # Handle tool calls
        elif payload_type == "function_call":
            msg = {"role": "assistant", "content": [{
                "type": "tool_call",
                "name": payload.get("name", ""),
                "input": json.loads(payload.get("arguments", "{}"))
            }]}
            messages.append(msg)

        # Handle tool results
        elif payload_type == "function_call_output":
            output = payload.get("output", "")
            msg = {"role": "tool", "content": [{
                "type": "tool_result",
                "content": output[:1000] if len(str(output)) > 1000 else output
            }]}
            messages.append(msg)

    return messages


def parse_gemini_json(data: list) -> list[dict]:
    """Parse Gemini JSON format."""
    messages = []
    for entry in data:
        role = entry.get("role", "unknown")
        msg = {"role": role, "content": []}

        for part in entry.get("parts", []):
            if "text" in part:
                msg["content"].append({"type": "text", "text": part["text"]})
            elif "functionCall" in part:
                fc = part["functionCall"]
                msg["content"].append({
                    "type": "tool_call",
                    "name": fc.get("name", ""),
                    "input": fc.get("args", {})
                })
            elif "functionResponse" in part:
                fr = part["functionResponse"]
                msg["content"].append({
                    "type": "tool_result",
                    "name": fr.get("name", ""),
                    "content": fr.get("response", {})
                })

        messages.append(msg)
    return messages


# === Format Registry ===

FORMATS = {
    "claude": {
        "name": "Claude Code JSONL",
        "ext": ".jsonl",
        "parser": parse_claude_jsonl,
    },
    "codebuddy": {
        "name": "CodeBuddy JSONL",
        "ext": ".jsonl",
        "parser": parse_codebuddy_jsonl,
    },
    "codex": {
        "name": "OpenAI Codex JSONL",
        "ext": ".jsonl",
        "parser": parse_codex_jsonl,
    },
    "gemini": {
        "name": "Gemini JSON",
        "ext": ".json",
        "parser": parse_gemini_json,
    },
}


# === Markdown Renderer ===

def render_markdown(messages: list[dict]) -> str:
    """Render messages to Markdown."""
    lines = []

    for msg in messages:
        role = msg["role"].capitalize()
        lines.append(f"**{role}:**\n")

        for block in msg["content"]:
            if block["type"] == "text":
                text = block["text"].strip()
                if text:
                    lines.append(text)
                    lines.append("")

            elif block["type"] == "tool_call":
                name = block["name"]
                inp = json.dumps(block["input"], indent=2, ensure_ascii=False)
                lines.append(f"```python\n# Tool: {name}\n{inp}\n```")
                lines.append("")

            elif block["type"] == "tool_result":
                content = block.get("content", "")
                if isinstance(content, dict):
                    content = json.dumps(content, indent=2, ensure_ascii=False)
                name = block.get("name", "result")
                content_str = str(content)
                if len(content_str) > 500:
                    content_str = content_str[:500] + "\n\n[truncated...]"
                lines.append(f"```json\n# {name}\n{content_str}\n```")
                lines.append("")

        lines.append("---\n")

    return "\n".join(lines)


# === Interactive Format Selection ===

def select_format_interactive() -> str:
    """Ask user to select format."""
    print("Select input format:")
    for i, (key, info) in enumerate(FORMATS.items(), 1):
        print(f"  {i}. {info['name']} ({key})")

    while True:
        try:
            choice = input("\nEnter number (1-3): ").strip()
            idx = int(choice) - 1
            return list(FORMATS.keys())[idx]
        except (ValueError, IndexError):
            print("Invalid choice. Try again.")


# === Main ===

def main():
    parser = argparse.ArgumentParser(
        description="Convert AI conversation logs to Markdown"
    )
    parser.add_argument("input", help="Input JSON/JSONL file")
    parser.add_argument("output", help="Output Markdown file")
    parser.add_argument(
        "-f", "--format",
        choices=list(FORMATS.keys()),
        help="Input format (if not specified, will prompt interactively)"
    )

    args = parser.parse_args()

    # Determine format
    fmt = args.format
    if not fmt:
        fmt = select_format_interactive()
        print(f"\nUsing format: {FORMATS[fmt]['name']}\n")

    # Read input
    try:
        with open(args.input, 'r', encoding='utf-8') as f:
            if FORMATS[fmt]["ext"] == ".jsonl":
                lines = f.readlines()
                messages = FORMATS[fmt]["parser"](lines)
            else:
                data = json.load(f)
                messages = FORMATS[fmt]["parser"](data)
    except FileNotFoundError:
        print(f"Error: File not found: {args.input}", file=sys.stderr)
        sys.exit(1)
    except json.JSONDecodeError as e:
        print(f"Error: Invalid JSON - {e}", file=sys.stderr)
        sys.exit(1)

    # Render and write
    markdown = render_markdown(messages)

    with open(args.output, 'w', encoding='utf-8') as f:
        f.write(markdown)

    print(f"Converted {len(messages)} messages to {args.output}")


if __name__ == "__main__":
    main()

