#!/usr/bin/env python3
"""
convert.py - Convert AI conversation logs to Markdown (v2.1)

A small, efficient tool to transform AI JSON/JSONL logs into readable Markdown.
Follows Linus's philosophy: Separation of mechanism and policy.

Usage:
    python convert.py -f FORMAT input.json output.md
    python convert.py input.json output.md  # interactive selection
"""

import argparse
import json
import re
import sys
from collections import deque
from pathlib import Path
from typing import Any, Generator, Iterable, Optional, Protocol


# === Types and Models ===

class MessageBlock(dict):
    """A single block of content (text, tool_call, or tool_result)."""
    pass

class InternalMessage(dict):
    """Internal normalized message: {'role': str, 'content': list[MessageBlock]}"""
    pass


# === Content Cleaning ===

CLEAN_PATTERNS = [
    # Claude Code patterns
    (re.compile(r'<local-command-caveat>.*?</local-command-caveat>', re.DOTALL), ""),
    (re.compile(r'<local-command-stdout>(.*?)</local-command-stdout>', re.DOTALL), r"\1"),
    (re.compile(r'<local-command-stderr>(.*?)</local-command-stderr>', re.DOTALL), r"\1"),
    (re.compile(r'<command-name>(.*?)</command-name>\s*<command-message>(.*?)</command-message>\s*<command-args>(.*?)</command-args>', re.DOTALL), r"`\1 \2 \3`"),
    # CodeBuddy patterns
    (re.compile(r'<command-message>(.*?)</command-message>\s*<command-name>(.*?)</command-name>', re.DOTALL), r"`\2 \1`"),
    (re.compile(r'<thinking>.*?</thinking>', re.DOTALL), ""),
    (re.compile(r'\n{3,}'), "\n\n"),  # Collapse multiple blank lines
]

def clean_text(text: str) -> str:
    """Apply global text cleaning patterns."""
    if not isinstance(text, str):
        return str(text)
    for pattern, replacement in CLEAN_PATTERNS:
        text = pattern.sub(replacement, text)
    return text.strip()


# === Streaming Loader ===

def stream_json_objects(file_path: str, format_ext: str) -> Generator[Any, None, None]:
    """Yield JSON objects from a file without loading everything into memory."""
    try:
        with open(file_path, 'r', encoding='utf-8') as f:
            if format_ext == ".jsonl":
                for line_num, line in enumerate(f, 1):
                    if not line.strip():
                        continue
                    try:
                        yield json.loads(line)
                    except json.JSONDecodeError as e:
                        print(f"Warning: Skip malformed JSON at line {line_num}: {e}", file=sys.stderr)
            else:
                # For standard JSON, we still have to load it (unless we use ijson)
                # But we assume standard JSON files for these tools are reasonably sized.
                data = json.load(f)
                if isinstance(data, list):
                    yield from data
                else:
                    yield data
    except FileNotFoundError:
        print(f"Error: File not found: {file_path}", file=sys.stderr)
        sys.exit(1)


# === Mappers (Policy) ===

def map_claude_entry(entry: dict) -> Generator[InternalMessage, None, None]:
    """Map a Claude Code log entry to internal messages."""
    msg_type = entry.get("type", "")
    if msg_type not in ("user", "assistant"):
        return

    # Skip meta/summary
    if entry.get("isMeta") or entry.get("isSummary"):
        return

    data = entry.get("message", {})
    role = data.get("role", msg_type)
    content = data.get("content", [])

    if isinstance(content, str):
        content = [{"type": "text", "text": content}]

    msg = {"role": role, "content": []}
    for block in content:
        btype = block.get("type")
        if btype == "text":
            text = clean_text(block.get("text", ""))
            if text:
                msg["content"].append({"type": "text", "text": text})
        elif btype == "tool_use":
            msg["content"].append({
                "type": "tool_call",
                "name": block.get("name", ""),
                "input": block.get("input", {})
            })
        elif btype == "tool_result":
            msg["content"].append({
                "type": "tool_result",
                "content": block.get("content", "")
            })

    if msg["content"]:
        yield msg


def map_codebuddy_entry(entry: dict) -> Generator[InternalMessage, None, None]:
    """Map a CodeBuddy log entry to internal messages."""
    etype = entry.get("type", "")

    if etype == "message":
        role = entry.get("role", "unknown")
        msg = {"role": role, "content": []}
        for block in entry.get("content", []):
            if block.get("type") in ("input_text", "output_text"):
                text = clean_text(block.get("text", ""))
                if text:
                    msg["content"].append({"type": "text", "text": text})
        if msg["content"]:
            yield msg

    elif etype == "function_call":
        args = entry.get("arguments", "{}")
        yield {"role": "assistant", "content": [{
            "type": "tool_call",
            "name": entry.get("name", ""),
            "input": json.loads(args) if isinstance(args, str) else args
        }]}

    elif etype == "function_call_result":
        output = entry.get("output", {})
        text = output.get("text", "") if isinstance(output, dict) else str(output)
        yield {"role": "tool", "content": [{
            "type": "tool_result",
            "name": entry.get("name", ""),
            "content": text
        }]}


def map_codex_entry(entry: dict) -> Generator[InternalMessage, None, None]:
    """Map an OpenAI Codex log entry to internal messages."""
    if entry.get("type") != "response_item":
        return

    payload = entry.get("payload", {})
    ptype = payload.get("type", "")

    if ptype == "message":
        role = payload.get("role", "unknown")
        if role in ("developer", "system"):
            return
        msg = {"role": role, "content": []}
        for block in payload.get("content", []):
            if block.get("type") in ("input_text", "output_text"):
                text = clean_text(block.get("text", ""))
                if text:
                    msg["content"].append({"type": "text", "text": text})
        if msg["content"]:
            yield msg

    elif ptype == "function_call":
        args = payload.get("arguments", "{}")
        yield {"role": "assistant", "content": [{
            "type": "tool_call",
            "name": payload.get("name", ""),
            "input": json.loads(args) if isinstance(args, str) else args
        }]}

    elif ptype == "function_call_output":
        output = payload.get("output", "")
        yield {"role": "tool", "content": [{
            "type": "tool_result",
            "content": output
        }]}


def map_gemini_entry(entry: dict) -> Generator[InternalMessage, None, None]:
    """Map a Gemini log entry to internal messages."""
    role = entry.get("role", "unknown")
    msg = {"role": role, "content": []}

    for part in entry.get("parts", []):
        if "text" in part:
            text = clean_text(part["text"])
            if text:
                msg["content"].append({"type": "text", "text": text})
        elif "functionCall" in part:
            fc = part["functionCall"]
            msg["content"].append({
                "type": "tool_call",
                "name": fc.get("name", ""),
                "input": fc.get("args", {})
            })
        elif "functionResponse" in part:
            fr = part["functionResponse"]
            msg["content"].append({
                "type": "tool_result",
                "name": fr.get("name", ""),
                "content": fr.get("response", {})
            })

    if msg["content"]:
        yield msg


# === Format Registry ===

FORMATS = {
    "claude": {
        "name": "Claude Code JSONL",
        "ext": ".jsonl",
        "mapper": map_claude_entry,
    },
    "codebuddy": {
        "name": "CodeBuddy JSONL",
        "ext": ".jsonl",
        "mapper": map_codebuddy_entry,
    },
    "codex": {
        "name": "OpenAI Codex JSONL",
        "ext": ".jsonl",
        "mapper": map_codex_entry,
    },
    "gemini": {
        "name": "Gemini JSON",
        "ext": ".json",
        "mapper": map_gemini_entry,
    },
}


# === Markdown Renderer (Stream-ready) ===

def render_markdown_stream(messages: Iterable[InternalMessage]) -> Generator[str, None, None]:
    """Yield Markdown lines from a message stream."""
    for msg in messages:
        role = msg["role"].capitalize()
        yield f"**{role}:**\n\n"

        for block in msg["content"]:
            btype = block["type"]
            if btype == "text":
                yield f"{block['text']}\n\n"

            elif btype == "tool_call":
                name = block["name"]
                inp = json.dumps(block["input"], indent=2, ensure_ascii=False)
                yield f"```python\n# Tool: {name}\n{inp}\n```\n\n"

            elif btype == "tool_result":
                content = block.get("content", "")
                if isinstance(content, dict):
                    content = json.dumps(content, indent=2, ensure_ascii=False)
                name = block.get("name", "result")
                content_str = str(content)
                if len(content_str) > 5000:
                    content_str = content_str[:5000] + "\n\n[truncated...]"
                yield f"```json\n# {name}\n{content_str}\n```\n\n"

        yield "---\n\n"


# === Interaction ===

def select_format_interactive() -> str:
    """Ask user to select format."""
    print("Select input format:")
    keys = list(FORMATS.keys())
    for i, key in enumerate(keys, 1):
        print(f"  {i}. {FORMATS[key]['name']} ({key})")

    while True:
        try:
            choice = input(f"\nEnter number (1-{len(keys)}): ").strip()
            return keys[int(choice) - 1]
        except (ValueError, IndexError):
            print("Invalid choice. Try again.")


# === Main ===

def main():
    parser = argparse.ArgumentParser(
        description="Convert AI conversation logs to Markdown (v2.1)"
    )
    parser.add_argument("input", help="Input JSON/JSONL file")
    parser.add_argument("output", help="Output Markdown file")
    parser.add_argument("-f", "--format", choices=list(FORMATS.keys()), help="Input format")

    args = parser.parse_args()

    fmt_key = args.format or select_format_interactive()
    fmt_info = FORMATS[fmt_key]
    print(f"Using format: {fmt_info['name']}")

    # Pipeline: Stream -> Map -> Render -> Write
    raw_objects = stream_json_objects(args.input, fmt_info["ext"])

    # Nested generator: raw -> messages
    def message_generator():
        for obj in raw_objects:
            yield from fmt_info["mapper"](obj)

    # Render stream
    count = 0
    try:
        with open(args.output, 'w', encoding='utf-8') as f:
            for chunk in render_markdown_stream(message_generator()):
                f.write(chunk)
                if chunk.startswith("**"):
                    count += 1
    except Exception as e:
        print(f"Error during conversion: {e}", file=sys.stderr)
        sys.exit(1)

    print(f"Successfully converted {count} messages to {args.output}")


if __name__ == "__main__":
    main()

