    (re.compile(r'<local-command-stdout>(.*?)</local-command-stdout>', re.DOTALL), r"\1"),
    (re.compile(r'<local-command-stderr>(.*?)</local-command-stderr>', re.DOTALL), r"\1"),
    (re.compile(r'<command-name>(.*?)</command-name>\s*<command-message>(.*?)</command-message>\s*<command-args>(.*?)</command-args>', re.DOTALL), r"`\1 \2 \3`"),
    # CodeBuddy patterns
    (re.compile(r'<command-message>(.*?)</command-message>\s*<command-name>(.*?)</command-name>', re.DOTALL), r"`\2 \1`"),
    (re.compile(r'<thinking>.*?</thinking>', re.DOTALL), ""),
    (re.compile(r'\n{3,}'), "\n\n"),  # Collapse multiple blank lines
]

def clean_text(text: str) -> str:
    """Apply global text cleaning patterns."""
    if not isinstance(text, str):
        return str(text)
    for pattern, replacement in CLEAN_PATTERNS:
        text = pattern.sub(replacement, text)
    return text.strip()


# === Streaming Loader ===

def stream_json_objects(file_path: str, format_ext: str) -> Generator[Any, None, None]:
    """Yield JSON objects from a file without loading everything into memory."""
    try:
        with open(file_path, 'r', encoding='utf-8') as f:
            if format_ext == ".jsonl":
                for line_num, line in enumerate(f, 1):
                    if not line.strip():
                        continue
                    try:
                        yield json.loads(line)
                    except json.JSONDecodeError as e:
                        print(f"Warning: Skip malformed JSON at line {line_num}: {e}", file=sys.stderr)
            else:
                # For standard JSON, we still have to load it (unless we use ijson)
                # But we assume standard JSON files for these tools are reasonably sized.
                data = json.load(f)
                if isinstance(data, list):
                    yield from data
                else:
                    yield data
    except FileNotFoundError:
        print(f"Error: File not found: {file_path}", file=sys.stderr)
        sys.exit(1)


# === Mappers (Policy) ===

def map_claude_entry(entry: dict) -> Generator[InternalMessage, None, None]:
    """Map a Claude Code log entry to internal messages."""
    msg_type = entry.get("type", "")
    if msg_type not in ("user", "assistant"):
        return

    # Skip meta/summary
    if entry.get("isMeta") or entry.get("isSummary"):
        return

    data = entry.get("message", {})
    role = data.get("role", msg_type)
    content = data.get("content", [])

    if isinstance(content, str):
        content = [{"type": "text", "text": content}]

    msg = {"role": role, "content": []}
    for block in content:
        btype = block.get("type")
        if btype == "text":
            text = clean_text(block.get("text", ""))
            if text:
                msg["content"].append({"type": "text", "text": text})
        elif btype == "tool_use":
            msg["content"].append({
                "type": "tool_call",
                "name": block.get("name", ""),
                "input": block.get("input", {})
            })
        elif btype == "tool_result":
            msg["content"].append({
                "type": "tool_result",
                "content": block.get("content", "")
            })

    if msg["content"]:
        yield msg


def map_codebuddy_entry(entry: dict) -> Generator[InternalMessage, None, None]:
    """Map a CodeBuddy log entry to internal messages."""
    etype = entry.get("type", "")

    if etype == "message":
        role = entry.get("role", "unknown")
        msg = {"role": role, "content": []}
        for block in entry.get("content", []):
            if block.get("type") in ("input_text", "output_text"):
                text = clean_text(block.get("text", ""))
                if text:
                    msg["content"].append({"type": "text", "text": text})
        if msg["content"]:
            yield msg

    elif etype == "function_call":
        args = entry.get("arguments", "{}")
        yield {"role": "assistant", "content": [{
            "type": "tool_call",
            "name": entry.get("name", ""),
            "input": json.loads(args) if isinstance(args, str) else args
        }]}

    elif etype == "function_call_result":
        output = entry.get("output", {})
        text = output.get("text", "") if isinstance(output, dict) else str(output)
        yield {"role": "tool", "content": [{
            "type": "tool_result",
            "name": entry.get("name", ""),
            "content": text
        }]}


def map_codex_entry(entry: dict) -> Generator[InternalMessage, None, None]:
    """Map an OpenAI Codex log entry to internal messages."""
    if entry.get("type") != "response_item":
        return

    payload = entry.get("payload", {})
